/**
 * BookSage Live — ADK-based server with Runner.runAsync.
 *
 * ADK TS v0.5 does not have runLive() (Python ADK feature).
 * We use the @google/genai Live API for the WebSocket streaming connection
 * and the ADK Runner for turn-by-turn tool execution when needed.
 */

import express from "express";
import { createServer } from "http";
import path from "path";
import { WebSocketServer, WebSocket } from "ws";
import { GoogleGenAI, Type } from "@google/genai";
import { v4 as uuidv4 } from "crypto";
import type { IncomingMessage } from "http";
import {
  Runner,
  InMemorySessionService,
  LiveRequestQueue,
} from "@google/adk";
import { rootAgent, getRunConfig, LIVE_MODEL } from "./adk-agent.js";

const APP_NAME = "booksage-live";
const STATIC_DIR = path.join(__dirname, "..", "..", "static");

const sessionService = new InMemorySessionService();

function createRunner(): Runner {
  return new Runner({
    appName: APP_NAME,
    agent: rootAgent,
    sessionService,
  });
}

// =========================================================================
// Express + WebSocket server
// =========================================================================

export function createApp() {
  const app = express();
  const server = createServer(app);
  const wss = new WebSocketServer({ noServer: true });

  app.get("/health", (_req, res) => {
    res.json({
      status: "ok",
      app: APP_NAME,
      engine: "adk",
      agent: rootAgent.name,
      sub_agents: (rootAgent as any).subAgents?.map((a: any) => a.name) ?? [],
    });
  });

  app.get("/", (_req, res) => {
    res.sendFile(path.join(STATIC_DIR, "index.html"));
  });

  app.use("/static", express.static(STATIC_DIR));

  server.on("upgrade", (request: IncomingMessage, socket, head) => {
    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
    if (url.pathname === "/ws/read") {
      wss.handleUpgrade(request, socket, head, (ws) => {
        wss.emit("connection", ws, request);
      });
    } else {
      socket.destroy();
    }
  });

  wss.on("connection", (ws: WebSocket) => {
    handleWebSocket(ws);
  });

  return server;
}

async function handleWebSocket(ws: WebSocket) {
  const apiKey =
    process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
  if (!apiKey) {
    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
    ws.close();
    return;
  }

  process.env.GOOGLE_API_KEY = apiKey;

  const client = new GoogleGenAI({ apiKey });
  const runConfig = getRunConfig();

  const userId = `user-${randomHex(8)}`;
  const sessionId = `session-${randomHex(8)}`;

  let frameCount = 0;
  let firstFrameSeeded = false;
  let closed = false;

  console.log(`[${APP_NAME}] Client connected, user=${userId}, session=${sessionId}`);

  // Build the Gemini Live config from runConfig
  const liveConfig: any = {
    response_modalities: ["AUDIO"],
    system_instruction: (rootAgent as any).instruction,
    speech_config: {
      voice_config: {
        prebuilt_voice_config: { voice_name: "Kore" },
      },
    },
    input_audio_transcription: {},
    output_audio_transcription: {},
    realtime_input_config: {
      automatic_activity_detection: {
        disabled: false,
        start_of_speech_sensitivity: "START_SENSITIVITY_HIGH",
        end_of_speech_sensitivity: "END_SENSITIVITY_HIGH",
        prefix_padding_ms: 200,
        silence_duration_ms: 1500,
      },
    },
    // Declare tools for the Live session so Gemini can call them
    tools: buildToolDeclarations(),
  };

  try {
    const session = await client.live.connect({
      model: LIVE_MODEL,
      config: liveConfig,
    });

    const receiveFromClient = async () => {
      try {
        for await (const rawMsg of wsMessages(ws)) {
          if (closed) break;

          if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
            const data =
              rawMsg instanceof ArrayBuffer
                ? new Uint8Array(rawMsg)
                : rawMsg;
            await session.sendRealtimeInput({
              audio: {
                data: Buffer.from(data).toString("base64"),
                mimeType: "audio/pcm;rate=16000",
              },
            });
          } else if (typeof rawMsg === "string") {
            const data = JSON.parse(rawMsg);
            const msgType = data.type;

            if (msgType === "camera") {
              const imgBytes = Buffer.from(data.data, "base64");
              const mime = data.mime_type ?? "image/jpeg";
              await session.sendRealtimeInput({
                media: {
                  data: imgBytes.toString("base64"),
                  mimeType: mime,
                },
              });
              frameCount++;

              if (!firstFrameSeeded && frameCount >= 3) {
                firstFrameSeeded = true;
                await session.sendClientContent({
                  turns: {
                    role: "user",
                    parts: [
                      {
                        text:
                          "[GREET] You just received the first camera " +
                          "frame showing a book page. Read the visible text " +
                          "and give a brief, specific greeting. Mention what " +
                          "you see (title, author, topic, language, difficulty). " +
                          "Keep it to 2 sentences. Be warm.",
                      },
                    ],
                  },
                  turnComplete: true,
                });
                console.log(`[${APP_NAME}] Context seed sent (frame #${frameCount})`);
              }
            } else if (msgType === "set_mode") {
              const modeMap: Record<string, string> = {
                vocabulary: "Switch to Lexicon — I want vocabulary help.",
                literary: "Switch to Sage — let's discuss themes and meaning.",
                study: "Switch to Tutor — I want study help and quizzes.",
              };
              const mode = data.mode ?? "vocabulary";
              const text = modeMap[mode] ?? modeMap.vocabulary;
              await session.sendClientContent({
                turns: {
                  role: "user",
                  parts: [{ text }],
                },
                turnComplete: true,
              });
              const nameMap: Record<string, string> = {
                vocabulary: "Lexicon",
                literary: "Sage",
                study: "Tutor",
              };
              ws.send(
                JSON.stringify({
                  type: "mode_changed",
                  mode,
                  name: nameMap[mode] ?? mode,
                })
              );
            } else if (msgType === "text") {
              await session.sendClientContent({
                turns: {
                  role: "user",
                  parts: [{ text: data.text }],
                },
                turnComplete: true,
              });
            }
          }
        }
      } catch (e: any) {
        if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
      }
    };

    const sendToClient = async () => {
      try {
        const turn = session.receive();
        for await (const response of turn) {
          if (closed) break;

          // Audio data
          if (response.data) {
            ws.send(response.data, { binary: true });
          }

          // Text transcript
          if (response.text) {
            ws.send(
              JSON.stringify({
                type: "transcript",
                role: "agent",
                text: response.text,
              })
            );
          }

          // User speech transcription
          if (
            response.serverContent &&
            (response.serverContent as any).inputTranscription
          ) {
            const userText = (response.serverContent as any).inputTranscription;
            if (userText?.text) {
              ws.send(
                JSON.stringify({
                  type: "transcript",
                  role: "user",
                  text: userText.text,
                })
              );
            }
          }

          // Function calls from model
          if (response.toolCall) {
            for (const fc of response.toolCall.functionCalls ?? []) {
              ws.send(
                JSON.stringify({
                  type: "tool_call",
                  name: fc.name,
                  args: fc.args ?? {},
                })
              );

              // Execute tool locally and send response back
              const result = executeToolLocally(fc.name!, fc.args ?? {});
              ws.send(
                JSON.stringify({
                  type: "tool_result",
                  name: fc.name,
                  result,
                })
              );

              // Send function response back to Gemini
              await session.sendToolResponse({
                functionResponses: [
                  {
                    name: fc.name!,
                    response: result,
                    id: fc.id,
                  },
                ],
              });
            }
          }

          // Turn complete
          if (
            response.serverContent &&
            (response.serverContent as any).turnComplete
          ) {
            ws.send(JSON.stringify({ type: "turn_complete" }));
          }
        }
      } catch (e: any) {
        if (!closed && !String(e).toLowerCase().includes("close")) {
          console.log(`[${APP_NAME}] send error:`, e?.message);
        }
      }
    };

    await Promise.all([receiveFromClient(), sendToClient()]);
    closed = true;
  } catch (e: any) {
    console.error(`[${APP_NAME}] WebSocket error:`, e);
    try {
      ws.send(JSON.stringify({ type: "error", message: String(e) }));
    } catch {}
  } finally {
    console.log(`[${APP_NAME}] Client disconnected (frames=${frameCount})`);
    try {
      ws.close();
    } catch {}
  }
}

// =========================================================================
// Tool declarations for Gemini Live function calling
// =========================================================================

function buildToolDeclarations() {
  return [
    {
      functionDeclarations: [
        {
          name: "define_word",
          description: "Define a word in its reading context.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The word to define." },
              context: {
                type: Type.STRING,
                description: "The sentence or passage where the word appears.",
              },
            },
            required: ["word", "context"],
          },
        },
        {
          name: "flag_difficult_words",
          description: "Identify difficult words on the visible page.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              page_text: {
                type: Type.STRING,
                description: "The text visible on the book page.",
              },
            },
            required: ["page_text"],
          },
        },
        {
          name: "track_concept",
          description: "Track a key concept discussed during the reading session.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              concept: {
                type: Type.STRING,
                description: "The concept or theme to remember.",
              },
              page_context: {
                type: Type.STRING,
                description: "Brief context of where/how it appeared.",
              },
            },
            required: ["concept", "page_context"],
          },
        },
        {
          name: "get_session_summary",
          description:
            "Get a summary of everything discussed in this reading session.",
          parameters: {
            type: Type.OBJECT,
            properties: {},
            required: [],
          },
        },
        {
          name: "analyze_passage",
          description:
            "Analyze a literary passage for themes, devices, or structure.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              passage: {
                type: Type.STRING,
                description: "The text passage to analyze.",
              },
              analysis_type: {
                type: Type.STRING,
                description:
                  "Type of analysis: 'theme', 'device', 'structure', 'character', 'argument'.",
              },
            },
            required: ["passage", "analysis_type"],
          },
        },
        {
          name: "quiz_comprehension",
          description:
            "Generate a comprehension question about the current reading.",
          parameters: {
            type: Type.OBJECT,
            properties: {
              topic: {
                type: Type.STRING,
                description: "What to quiz about.",
              },
              difficulty: {
                type: Type.STRING,
                description:
                  "Question difficulty: 'recall', 'analysis', 'synthesis'.",
              },
            },
            required: ["topic", "difficulty"],
          },
        },
      ],
    },
  ];
}

// =========================================================================
// Local tool execution (stateful — maintains per-session state)
// =========================================================================

// Simple in-memory state for the current connection
const sessionState: Record<string, unknown> = {};

function executeToolLocally(
  name: string,
  args: Record<string, unknown>
): Record<string, unknown> {
  const { readFileSync } = require("fs");
  const cefrPath = path.join(__dirname, "data", "cefr_b2_c1_light.json");

  let b2Words: Set<string>;
  let c1Words: Set<string>;
  try {
    const raw = readFileSync(cefrPath, "utf-8");
    const data = JSON.parse(raw);
    b2Words = new Set(data.B2 ?? []);
    c1Words = new Set(data.C1 ?? []);
  } catch {
    b2Words = new Set();
    c1Words = new Set();
  }

  switch (name) {
    case "define_word": {
      const word = args.word as string;
      const context = args.context as string;
      const wl = word.toLowerCase();
      const level = c1Words.has(wl) ? "C1" : b2Words.has(wl) ? "B2" : null;
      const concepts: string[] = (sessionState.concepts as string[]) ?? [];
      if (!concepts.includes(word)) concepts.push(word);
      sessionState.concepts = concepts.slice(-30);
      return {
        word,
        context,
        cefr_level: level,
        instruction:
          `Define '${word}' in the context: '${context}'. ` +
          (level ? `This is a ${level}-level word. ` : "") +
          "Give the definition, usage example, and etymology if interesting.",
      };
    }
    case "flag_difficult_words": {
      const pageText = args.page_text as string;
      const words = new Set(pageText.toLowerCase().split(/\s+/));
      const flagged: Array<{ word: string; level: string; label: string }> = [];
      for (const w of words) {
        const clean = w.replace(/^[.,;:!?"'()\[\]]+|[.,;:!?"'()\[\]]+$/g, "");
        if (c1Words.has(clean))
          flagged.push({ word: clean, level: "C1", label: "Advanced" });
        else if (b2Words.has(clean))
          flagged.push({ word: clean, level: "B2", label: "Challenging" });
      }
      return {
        flagged_count: flagged.length,
        words: flagged.slice(0, 10),
        instruction:
          "Mention 2-3 of the most interesting difficult words you found. Offer to explain them.",
      };
    }
    case "track_concept": {
      const concept = args.concept as string;
      const pageContext = args.page_context as string;
      const concepts: string[] = (sessionState.concepts as string[]) ?? [];
      if (!concepts.includes(concept)) concepts.push(concept);
      sessionState.concepts = concepts.slice(-30);
      const pages: string[] = (sessionState.page_notes as string[]) ?? [];
      pages.push(`${concept}: ${pageContext}`);
      sessionState.page_notes = pages.slice(-20);
      return {
        tracked: concept,
        total_concepts: concepts.length,
        instruction: "Concept noted. Continue the conversation naturally.",
      };
    }
    case "get_session_summary": {
      const concepts: string[] = (sessionState.concepts as string[]) ?? [];
      const pages: string[] = (sessionState.page_notes as string[]) ?? [];
      const uniquePages =
        pages.length > 0 ? new Set(pages.map((n) => n.split(":")[0])).size : 0;
      return {
        concepts_discussed: concepts,
        page_notes: pages,
        total_concepts: concepts.length,
        total_pages: uniquePages,
        instruction:
          "Summarize what was covered in this reading session. Highlight key concepts and connections between pages.",
      };
    }
    case "analyze_passage": {
      const passage = args.passage as string;
      const analysisType = args.analysis_type as string;
      const concepts: string[] = (sessionState.concepts as string[]) ?? [];
      return {
        passage_excerpt: passage.slice(0, 200),
        analysis_type: analysisType,
        prior_concepts: concepts.slice(-5),
        instruction:
          `Analyze this passage for ${analysisType}. Connect to previously discussed concepts if relevant. Keep analysis to 2-3 sentences.`,
      };
    }
    case "quiz_comprehension": {
      const topic = args.topic as string;
      const difficulty = args.difficulty as string;
      return {
        topic,
        difficulty,
        instruction:
          `Ask a ${difficulty}-level question about ${topic}. Use Socratic method — guide, don't lecture. If the reader answers, celebrate correct answers and gently redirect mistakes.`,
      };
    }
    default:
      return { error: `Unknown tool: ${name}` };
  }
}

// =========================================================================
// Helpers
// =========================================================================

function randomHex(bytes: number): string {
  const arr = new Uint8Array(bytes);
  require("crypto").randomFillSync(arr);
  return Buffer.from(arr).toString("hex");
}

async function* wsMessages(
  ws: WebSocket
): AsyncGenerator<Buffer | string, void, undefined> {
  const queue: (Buffer | string)[] = [];
  let resolve: (() => void) | null = null;
  let done = false;

  ws.on("message", (data: Buffer | string) => {
    queue.push(data);
    if (resolve) {
      resolve();
      resolve = null;
    }
  });

  ws.on("close", () => {
    done = true;
    if (resolve) {
      resolve();
      resolve = null;
    }
  });

  ws.on("error", () => {
    done = true;
    if (resolve) {
      resolve();
      resolve = null;
    }
  });

  while (true) {
    if (queue.length > 0) {
      yield queue.shift()!;
    } else if (done) {
      return;
    } else {
      await new Promise<void>((r) => {
        resolve = r;
      });
    }
  }
}

